  ('social-worker-moex-00181', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理學大師彼得聖吉（PeterM.Senge）的學習型組織主張組織成員需透過五項修練來觀察並掌握 環境變化，改變舊思維不要固執己見，要勇於突破障礙才能創新，屬於那一項修練要素？', '["自我超越（personalmastery）", "團隊學習（teamlearning）", "建立共同願景（sharevision）", "改進心智模式（improvementalmodels）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00182', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '科層管理又稱為韋伯主義，其中官僚組織的科層決定了管理運作的基礎。韋伯在《經濟與社會》 一書中所探討的官僚組織，下列特徵何者錯誤？', '["職有專責", "規章治事", "分層負責", "強調授權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00183', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'X理論與Y理論係由麥格雷特（McGregor）提出，有關Y理論對管理的主張，下列敘述何者錯 誤？', '["強調分權與授權", "管理要採取引導的方式", "組織的要求重於個人需要", "管理的措施應具有內在報酬的作用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00184', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '新公共管理使1980年代歐洲福利國家服務市場產生變革，有關其運作模式之敘述，下列何者錯誤？', '["係以市場取向的公共選擇理論為基礎", "提升政治決策對公共服務管理的直接干預", "透過民營化或準市場的模式運作", "強調服務使用者對服務供給的選擇權與發言權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00185', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關社會企業特性的描述，下列何者錯誤？', '["一種以創造弱勢者或環境之利益為基礎的組織所提供的財物或服務", "介於政府與志願部門之間", "欲以市場／經濟為手段來實現公益／社會的目的", "透過銷售財物或服務以創造收益，進而改善弱勢者或環境的不利處境"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00186', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '一個服務身心障礙者的機構向政府申請補助，他們在計畫書寫到：「本市身心障礙者人數逐年增 加，但是相關福利預算卻是不增反減，相較於人口數縮減的兒童少年，福利預算卻是緩慢增加， 反映出資源配置的不合理，有必要改善」。這樣的訴求突顯的是那一種需求？', '["感覺性需求", "規範性需求", "表達性需求", "比較性需求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00187', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關需求評量與方案內容之間的關係，下列敘述何者正確？', '["先決定方案裡的服務項目和作法，再來進行服務對象的需求評量", "執行方案之後蒐集成果做成紀錄，稱之為需求評量", "需求評量是為了蒐集資訊，以決定方案的目標和適宜的作法", "基於社會工作的價值，二個部分最好都不要有服務對象的參與或觀點"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00188', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在以成效為導向的方案規劃與評估之邏輯模式（logic model）中，有關資源投入運作過程，係屬 該模式的何種元素？', '["設定目標及目的", "服務設計", "服務產出", "成效評估"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00189', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關方案正式執行前進行的評估，不包括下列何者？', '["需求評量", "投入評估", "可行性評估", "效率評估"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00190', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關方案服務品質相關的向度，下列敘述何者錯誤？', '["「保證性」是指工作人員友善、有禮、體貼、以及具專業知識的程度", "「人性化」是指服務對象能以其可理解的語言，隨時獲得與產品或服務相關的資訊", "「一致性」是指產品或服務符合標準之程度", "「安全性」是指在無風險的安全設施中提供產品或服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
